def validate(args, output):
    strs = args[0]
    if not isinstance(output, list):
        return False
    from collections import Counter
    def sig(w):
        return ''.join(sorted(w))
    # 1. partition: the flattened output is exactly the input multiset
    flat = []
    for group in output:
        if not isinstance(group, list) or len(group) == 0:
            return False
        for w in group:
            if not isinstance(w, str):
                return False
            flat.append(w)
    if Counter(flat) != Counter(strs):
        return False
    # 2. each group is internally all anagrams
    group_sigs = []
    for group in output:
        s0 = sig(group[0])
        for w in group:
            if sig(w) != s0:
                return False
        group_sigs.append(s0)
    # 3. maximality: distinct groups must not share a signature
    if len(set(group_sigs)) != len(group_sigs):
        return False
    return True

