function validate(args, output) {
    const strs = args[0];
    if (!Array.isArray(output)) return false;
    const sig = (w) => w.split('').sort().join('');
    function counter(arr) {
        const m = new Map();
        for (const v of arr) m.set(v, (m.get(v) || 0) + 1);
        return m;
    }
    const flat = [];
    const groupSigs = [];
    for (const group of output) {
        if (!Array.isArray(group) || group.length === 0) return false;
        for (const w of group) {
            if (typeof w !== 'string') return false;
            flat.push(w);
        }
        const s0 = sig(group[0]);
        for (const w of group) if (sig(w) !== s0) return false;
        groupSigs.push(s0);
    }
    const a = counter(flat), b = counter(strs);
    if (a.size !== b.size) return false;
    for (const [k, v] of a) if (b.get(k) !== v) return false;
    if (new Set(groupSigs).size !== groupSigs.length) return false;
    return true;
}

