class Solution:
    def groupAnagrams(self, strs):
        groups = []
        keys = []
        for w in strs:
            k = tuple(sorted(w))
            if k in keys:
                groups[keys.index(k)].append(w)
            else:
                keys.append(k)
                groups.append([w])
        for g in groups:
            g.sort()
        groups.sort(key=lambda g: (len(g), g))
        return groups

