class Solution:
    def groupAnagrams(self, strs):
        buckets = {}
        for w in strs:
            key = ''.join(sorted(w))
            buckets.setdefault(key, []).append(w)
        res = list(buckets.values())
        for g in res:
            g.sort()
        res.sort(key=lambda g: (len(g), g))
        return res

